var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"날마다 나쁜 꿈을 꾼다네.","JPN":"毎日悪夢を見るのだ。","ENG":"Every night, I find myself trapped in the same wretched dream.","TWN":"我每天都會做惡夢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"얼굴 모를 한 여인이 눈 앞에서 죽어가는 꿈이요.","JPN":"見知らぬ女性が目の前で死んでゆく夢でな。","ENG":"A woman whose face I do not recognize, dying right before my eyes.","TWN":"夢裡有個陌生女子在我眼前死去。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"여인은 제 목을 노리는 커다란 범과 마주하고 있으나, 내가 아무리 손을 뻗어도 닿지 않아.","JPN":"その女性は己の首を狙う大きな虎と向かい合っているのだが、某がいくら手を伸ばそうとも、まったく届かなくでな。","ENG":"A great tiger stands before her, poised for her throat, yet no matter how far I reach, I can't touch her.","TWN":"女人與虎視眈眈的老虎搏鬥，但無論我怎麼伸手，就是觸不到她。"},"stage":{"bg":"MS_1501_1","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그녀가 뒤를 돌아 나를 바라볼 즈음이면, 만개하듯 번지는 핏자국에 눈앞이 붉게 질려.","JPN":"その女性が振り返り某に目を向けると、飛び散る血しぶきに視野が埋め尽くされる。","ENG":"By the time she turns and looks my way, my vision is already stained red with blood spreading like petals.","TWN":"當她回頭望向我時，眼前便被大片的血跡給染得一片猩紅。"},"stage":{"bg":"WHITE","slots":{"L":null,"C":{"char_id":"VOICE_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 꿈에서 깨어나면, 뜻 모를 공허함이 새벽 안개처럼 밀려들어 숨통을 갑갑하게 조여오지.","JPN":"そうやって夢から覚めると、訳の分からぬ虚しさが夜明けの霧のごとく押し寄せ、息が苦しくなるのだ。","ENG":"And when I wake, that nameless emptiness creeps in like the dawn mist, pressing down on my chest.","TWN":"當我從夢裡驚醒後，一股莫名的空虛感如早晨的濃霧般襲來，緊緊地掐住我的喉嚨。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_FX_BLOOD_SPREAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"그 차오르는 갑갑함을 못 이겨 꼭두새벽의 거리를 내달리지만 변하는 건 없어.","JPN":"湧き上がるもどかしさに耐えきれず、早朝の街をがむしゃらに走っても、変わるものは何もない。","ENG":"To shake it off, I run through the streets before sunrise, but nothing ever changes.","TWN":"我無法忍受這股窒息感，於是在大清早地奪門而出，但卻沒有任何改變。"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"다음 날도, 또 그 다음 날도 같은 꿈을 꾸리란 것을… 나는 알고 있기 때문에.","JPN":"次の日も、その次の日も同じ夢を見るであろうことを……某は知っているからだ。","ENG":"I know well that tomorrow, and the day after, I'll encounter that same dream again.","TWN":"因為我知道，明天、後天，甚至是之後的每一天…我都會做相同的夢。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"가! 가! 빨리!","JPN":"急げ！　早く！","ENG":"Go! Go! Move it!","TWN":"動作快！快走！"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"제대로 털었겠지?","JPN":"ちゃんと持ってきたんだろうな？","ENG":"We cleaned 'em out, right?","TWN":"東西都有拿到吧？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"걱정 마. 샤레이드로 떠나서 떵떵거리며 살 만큼은 털었으니까.","JPN":"問題ないよ。シャレードで何不自由なく生きていけるぐらいは詰めたから。","ENG":"Relax. We've got enough to live large in Charade for years.","TWN":"放心吧，這些夠我們在查雷德過上衣食無憂的好日子。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"어이, 경찰들 따라붙었어! 곧 잡히겠는데?","JPN":"おい、警察が追って来てるぞ！　このままだと捕まるぞ！","ENG":"Hey, we got cops on our tail! They're closing in!","TWN":"喂！警察追上來了！不太妙！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"걱정 말고 계속 밟아. 작전대로만 해.","JPN":"気にせず加速しろ。作戦通りにやりゃいいんだ。","ENG":"Don't sweat it! Just keep driving, stick to the plan.","TWN":"沒事，繼續踩油門，照計劃進行！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"이봐. 교량 앞에 차단기 내려가 있잖아! 여기로 가는 거 맞아?","JPN":"なんだ、橋の前の遮断機が降りてるじゃないか！　本当にこっちで合ってるのか？","ENG":"Hey, the crossing gate's down up ahead! You sure we're going the right way?","TWN":"喂，你看！橋上的柵欄降下來了，確定是走這嗎？"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":null,"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"미친…! 이거 도개교잖아! 화물선이 오고 있다고!","JPN":"やばいよ……！　これ跳ね橋じゃん！　貨物船が近づいてくる！","ENG":"Damn it…! It's a drawbridge! There's a cargo ship coming through!","TWN":"該死…！那是開啟橋！有貨船要經過！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_A","text":{"KOREA":"쫄지 마! 멈추면 우리 다 끝장이라 생각해!","JPN":"ビビんな！　ここで止まったら俺たちは終わりだ！","ENG":"Don't chicken out! If we stop now, we're screwed for good!","TWN":"別緊張！停下來我們就死定了！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"젠장, 밟는다!","JPN":"くそっ、飛ばすぞ！","ENG":"Damn it, hold tight!","TWN":"可惡，油門催到底！"},"stage":{"bg":"HIGHWAY_NORMAL","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":{"char_id":"ROBBERY_NPC_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_B","text":{"KOREA":"휴우…","JPN":"ふう……","ENG":"Whew…","TWN":"呼… "},"stage":{"bg":"DONGDAEMUN","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBBERY_NPC_NULL_C","text":{"KOREA":"살았다. 조금만 늦었어도 추락할 뻔했어.","JPN":"危なかったな。一足遅かったら落ちるところだった。","ENG":"We made it. One second later and we'd have gone down with it.","TWN":"好險，差點就要掉進河裡了。"},"stage":{"bg":"DONGDAEMUN","slots":{"L":{"char_id":"ROBBERY_NPC_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"ROBBERY_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};